-- Migration 019 - Experiments import
--
-- Backfill the experiments table from the roasting spreadsheet
-- (Coffee Roasting - Spreadsheet (7).xlsx, Experiments tab).
--
-- Scope: 18 experiments across the 4 green_beans rows currently in the
-- database. The spreadsheet also tracks 16 experiments across 5 CGLE /
-- Forrest / Higuito beans whose green_beans rows have not been imported
-- yet; those will land in a follow-up sprint alongside the green_beans
-- backfill (out of scope here).
--
-- Idempotent: ON CONFLICT DO NOTHING keyed on the new
-- (user_id, green_bean_id, experiment_id) unique constraint.
--
-- green_bean_id and user_id resolve via subquery on green_beans.lot_id so
-- the migration is portable across environments (no hardcoded uuids).

BEGIN;

-- =====================================================================
-- Schema: unique constraint to enable ON CONFLICT
-- =====================================================================
ALTER TABLE experiments
  ADD CONSTRAINT experiments_user_bean_expid_unique
  UNIQUE (user_id, green_bean_id, experiment_id);

-- =====================================================================
-- Data: 18 experiments, grouped by green bean. Built via jsonb_to_recordset
-- so all string escaping is handled by JSON.
-- =====================================================================

-- Gesha Village - Surma - Gesha 1931 (2 rows, lot_id = 'GESHA-VILLAGE-SURMA-LOT-25-039')
WITH bean AS (SELECT id AS green_bean_id, user_id FROM green_beans WHERE lot_id = 'GESHA-VILLAGE-SURMA-LOT-25-039')
INSERT INTO experiments (
  user_id, green_bean_id,
  experiment_id, batch_ids, context, primary_question, control_baseline,
  shared_constants, variable_changed, levels_tested, expected_outcomes,
  failure_boundary, observed_outcome_a, observed_outcome_b, observed_outcome_c,
  observed_outcome_d, winner, key_insight, what_changes_going_forward
)
SELECT
  bean.user_id, bean.green_bean_id,
  rec.experiment_id, rec.batch_ids, rec.context, rec.primary_question, rec.control_baseline,
  rec.shared_constants, rec.variable_changed, rec.levels_tested, rec.expected_outcomes,
  rec.failure_boundary, rec.observed_outcome_a, rec.observed_outcome_b, rec.observed_outcome_c,
  rec.observed_outcome_d, rec.winner, rec.key_insight, rec.what_changes_going_forward
FROM bean,
  jsonb_to_recordset('[{"experiment_id": "GV-SURMA-DEV-ANCHOR", "batch_ids": "22, 23", "context": "After early roasts showed either muted florals (Batch 18) or underdevelopment (Batch 20), two development anchors were established to understand the extremes of expression vs structure.", "primary_question": "How does short vs long development affect Gesha floral expression, body, and balance?", "control_baseline": "None (exploratory anchor points)", "shared_constants": "Same green lot, same charge (100 g), same profile shape, same inlet strategy, same airflow and RPM, same evaluation methods", "variable_changed": "Development time", "levels_tested": "A: ~0:58 dev (Batch 22)\nB: ~1:10 dev (Batch 23)", "expected_outcomes": "A: Higher florals, lighter body, possible dryness\nB: More body and sweetness, muted florals", "failure_boundary": "Grassiness or sharp underdevelopment (too short); loss of Gesha identity and aromatics (too long)", "observed_outcome_a": "Strong Gesha florals consistently present across cupping and pourover; attack-forward and tea-like; body lighter and less integrated; slight hollowness and mild dryness when hot; improves with cooling but remains structurally underbuilt", "observed_outcome_b": "Rounder, more integrated body; higher sweetness and mid-palate weight; florals consistently muted and hidden in body; reads as high-quality light roast rather than distinctive Gesha", "observed_outcome_c": "N/A", "winner": "Batch 22 (A) for Gesha identity and floral expression", "key_insight": "Development time directly trades off floral clarity vs structural integration; Gesha aromatics peak earlier than optimal body development", "what_changes_going_forward": "Use short development as the aromatic ceiling, but search for a narrow window that adds structure without collapsing florals"}, {"experiment_id": "GV-SURMA-DEV-SWEEP", "batch_ids": "25, 26, 27", "context": "With anchors established, remaining green was used to tightly bracket the development-time inflection point to find the optimal balance between floral lift and structural integrity.", "primary_question": "Where is the development-time sweet spot that preserves Gesha florals while avoiding dryness or hollowness?", "control_baseline": "Batch 22 (0:58 dev) and Batch 23 (1:10 dev) as reference anchors", "shared_constants": "Same green lot, same profile, same charge (100 g), same inlet curve, same airflow/RPM, same drop logic (time-based, not BT-based)", "variable_changed": "Development time only", "levels_tested": "A: ~0:55 dev (Batch 25)\nB: ~1:03 dev (Batch 26)\nC: ~1:07 dev (Batch 27)", "expected_outcomes": "A: Maximum florals, risk of sharpness\nB: Best balance of florals and body\nC: Increased body, risk of floral collapse", "failure_boundary": "Dry, sharp finish (too short); ashy, muted, collapsed florals (too long)", "observed_outcome_a": "Most floral and Gesha-expressive roast across pourover; bright floral attack; cohesive as it cools; slight sharpness initially but no structural defects; clearly responds well to brewing", "observed_outcome_b": "Cleaner and more integrated body than A; florals present but muted; reads more balanced and forgiving; pleasant but less distinctive; brewing did not unlock additional aromatics", "observed_outcome_c": "Overdeveloped signal in pourover; ashy/campfire notes; florals collapsed; dull body; clearly crossed failure boundary", "winner": "Batch 25 (A)", "key_insight": "The optimal window for this Gesha is earlier than expected; a very narrow band exists where florals peak before structural degradation begins", "what_changes_going_forward": "Anchor future Gesha roasts near Batch 25 development and adjust body via brewing, not roast extension"}]') AS rec(
    experiment_id text, batch_ids text, context text, primary_question text,
    control_baseline text, shared_constants text, variable_changed text,
    levels_tested text, expected_outcomes text, failure_boundary text,
    observed_outcome_a text, observed_outcome_b text, observed_outcome_c text,
    observed_outcome_d text, winner text, key_insight text, what_changes_going_forward text
  )
ON CONFLICT (user_id, green_bean_id, experiment_id) DO NOTHING;

-- El Soccorro - Java Variety (6 rows, lot_id = 'GUA-SOC-JAVA-2024')
WITH bean AS (SELECT id AS green_bean_id, user_id FROM green_beans WHERE lot_id = 'GUA-SOC-JAVA-2024')
INSERT INTO experiments (
  user_id, green_bean_id,
  experiment_id, batch_ids, context, primary_question, control_baseline,
  shared_constants, variable_changed, levels_tested, expected_outcomes,
  failure_boundary, observed_outcome_a, observed_outcome_b, observed_outcome_c,
  observed_outcome_d, winner, key_insight, what_changes_going_forward
)
SELECT
  bean.user_id, bean.green_bean_id,
  rec.experiment_id, rec.batch_ids, rec.context, rec.primary_question, rec.control_baseline,
  rec.shared_constants, rec.variable_changed, rec.levels_tested, rec.expected_outcomes,
  rec.failure_boundary, rec.observed_outcome_a, rec.observed_outcome_b, rec.observed_outcome_c,
  rec.observed_outcome_d, rec.winner, rec.key_insight, rec.what_changes_going_forward
FROM bean,
  jsonb_to_recordset('[{"experiment_id": "JAVA-DEV-MOM-01", "batch_ids": "37, 38, 39", "context": "After initial blind cuppings of Batches #29–31, the Java variety consistently expressed a nutty/toasty core with improving balance as energy was redistributed. Batch #31 emerged as the most complete expression but still hinted at slight roast imprint. This experiment set isolates whether that character originates from post-crack development, Maillard peak energy, or overall roast speed.", "primary_question": "Which single lever—shorter development, lower Maillard peak energy, or faster roast momentum—most improves balance and clarity in El Socorro Java without sacrificing structure or sweetness?", "control_baseline": "Batch #31 (El Socorro Java – B)", "shared_constants": "Same green coffee and batch size (100 g)\nSame roaster (Roest L200 Ultra)\nSame inlet temperature curve shape (unless explicitly modified)\nSame fan, RPM, drum direction\nSame development target (~1:00) unless explicitly modified\nOne variable changed per experiment only", "variable_changed": "A: Development time\nB: Peak inlet temperature (Maillard energy)\nC: Roast speed / heat momentum (curve timing compression)", "levels_tested": "A: Reduce development from ~1:00 → ~0:30 (Batch #37)\nB: Lower peak inlet temperature by –2°C, keep timing and dev constant (Batch #38)\nC: Compress roast timing; peak at ~4:20, mid-Maillard at ~6:40, dev unchanged (Batch #39)", "expected_outcomes": "A: Cleaner, less drying finish; reduced roast imprint; risk of thinner body\nB: Softer nutty/toasty notes; improved sweetness and balance through body\nC: Increased liveliness and clarity; brighter acidity; risk of reduced cohesion", "failure_boundary": "Cup becomes thin, papery, or hollow\nSweetness collapses relative to acidity\nAcidity detaches from body\nFinish becomes sharp or short rather than clean", "observed_outcome_a": "What happened\nRoast imprint on the attack was still present when hot, though slightly less drying than the baseline.\nAs the cup cooled, acidity became more visible than in #39.\nNutty core remained, but with more character and contrast than the other two.\nBody held together reasonably well; did not collapse, but finish remained somewhat roast-leaning.\n\nInterpretation\nShortening development did not eliminate roast imprint, but it uncovered more acidity complexity as temperature dropped.\nThe coffee tolerated shorter dev without going papery or hollow.\nThis lever trades polish for expression.\n\nNet result - More expressive., Less refined., Not the cleanest, but not a failure.\n\nPourover cupping confirms that shortened development preserves varietal nut character and reveals latent acidity when hot, even though roast imprint remains. This expression translates better across brew methods than momentum-only acceleration.", "observed_outcome_b": "What happened\nRoast character remained dominant, especially in aroma.\nBody felt thinner than both #37 and #39.\nSweetness did not meaningfully improve.\nToast/roast notes persisted even as the cup cooled.\n\nInterpretation\nReducing peak inlet by –2°C did not meaningfully change the core flavor direction.\nThis Java appears not highly sensitive to small Maillard peak adjustments at this roast depth.\nLower energy weakened structure without improving clarity.\n\nNet result\nClear underperformer.\nThis lever, at least at –2°C, is low leverage for this coffee.", "observed_outcome_c": "What happened\nRoast aggression was most tamped down across temperatures.\nCup was smooth, cohesive, and balanced.\nAcidity was present but subdued and integrated.\n\nOverall profile felt slightly flat / monotone, lacking forward contrast.\nInterpretation\nEarlier momentum reduced perceived roast imprint without breaking structure.\nThis lever improves polish and integration.\nTrade-off is reduced expressiveness.\n\nNet result\nTechnically the cleanest and safest expression.\nHighest floor, not the highest ceiling.", "winner": "Batch #37 (Experiment A – shorter development) is the winner\n\nBatch #39’s apparent “cleanliness” in cupping was revealed to be polish-through-integration, not true clarity. In pourover, that polish collapses into roast-smoke dominance and loss of varietal signal.\n\nBatch #37, while imperfect, retains coffee-specific nutty + faint acidic character under extraction, which is the higher-value outcome.", "key_insight": "- Roast speed reduces perceived roast imprint in immersion, but development length more strongly governs extraction behavior and varietal legibility. Momentum alone risks flattening the cup and masking origin under percolation.\n- Peak Maillard energy (–2°C) is not a meaningful driver of flavor change here.\n- Shorter development increases contrast, but does not solve roast character on its own.\n- This Java prefers earlier energy delivery with controlled late support, rather than gentler or longer roasting.", "what_changes_going_forward": "Momentum-forward curves are useful only when paired with sufficient development control\n\nDevelopment time is not just a fine-tuning lever for this coffee; it directly affects brew-method robustness\n\nFuture experiments should combine moderate early momentum with slightly longer, gentler post-crack development, not minimal development"}, {"experiment_id": "JAVA-TYPICA-01", "batch_ids": "45, 46, 47", "context": "After reading Cultivar (Rob Hoos) on Typica, test whether El Socorro Java expresses “Typica-like” behavior and sweet spot sensitivity on Roest. Prior Java roasts were clean but leaned nutty/toasty caramel, implying landing late or too diffuse vs Typica window.", "primary_question": "Does this Java express more florality, citrus, and clarity if I increase early momentum slightly, and where is the boundary before the coffee becomes thin or papery?", "control_baseline": "Batch #31 (El Socorro Java – B)", "shared_constants": "Same core roast curve shape as Batch #31\nSame peak inlet, Maillard decline, development time, fan, RPM\nOnly one variable changed across A/B/C", "variable_changed": "Starting inlet temperature (early energy density / early momentum).", "levels_tested": "A: 190°C start, peak 253°C @ ~4:30.\nB: 192°C start, peak 253°C @ ~4:15. \nC: 195°C start, peak 253°C @ ~4:15.", "expected_outcomes": "A:  Floral lift without destablaizing body\nB: Clearer florals, tighter body, reduce nutty/toasty character \nC: deliberatly push past likely sweet spot to define boundary", "failure_boundary": "Boundary defined as: FC <7:15 and/or cup becomes thin, papery/starchy, acidity detached from sweetness.", "observed_outcome_a": "Small increase in early energy did not meaningfully lift florals or acidity\nNutty/toasty character remained dominant\nCup improved with cooling but remained body-forward\nStructure intact, but clarity unchanged", "observed_outcome_b": "Under pourover, roast imprint is reduced compared to A and C.\nAcidity appears consistently for the first time, but lacks contrast.\nCup is internally coherent but flat.\nRoast character resurfaces as the cup cools, thinning body and reducing clarity.\n\nInterpretation\nMedium early momentum successfully suppresses roast aggression, but also over-integrates the cup under percolation, muting expressiveness.", "observed_outcome_c": "Pourover strongly amplifies roast smoke when hot.\nCooling reveals improved sweetness, acidity, and body relative to #46.\nVarietal character is present but masked by excess roast momentum.\n\nInterpretation\nBoundary push does not cause structural failure, but overwhelms clarity under percolation. Shows that the coffee can carry more momentum, but the curve shape is wrong for extraction-sensitive brewing.", "winner": "Primary winner: Batch #46 (Experiment B)\nBest balance of structure and cleanliness under pourover, despite flatness.\n\nSecondary signal: Batch #47 contains more latent character, but requires a fundamentally different curve to surface it cleanly.", "key_insight": "Early momentum is necessary but not sufficient.\nThis Java is highly sensitive to curve shape, not just energy amount.\nPourover exposes over-integration and roast masking much more than immersion.\nThe problem is no longer “too little or too much energy” but how energy is distributed through Maillard.", "what_changes_going_forward": "Stop micro-tweaking start temperature alone.\nAnchor future work around Batch #46 momentum, but redesign the mid-Maillard energy delivery to restore contrast.\nFocus next experiments on:\nSmoother RoR decline into first crack\nSlightly longer or reshaped Maillard without reintroducing toast\nPreserving acidity visibility under percolation\nThis aligns exactly with the RoR-smoothing experiments you just queued up."}, {"experiment_id": "JAVA-DEV-46-01", "batch_ids": "56, 57, 58", "context": "#46 was preferred (low toast, acidity present) but felt flat/monotone; tune finish definition without changing momentum.", "primary_question": "With #46 momentum fixed, does shorter development restore separation/liveliness without going papery?", "control_baseline": "Batch #46", "shared_constants": "Same inlet curve as #46 (192@0:00, 253@4:15, 248@6:30, 248@12:00), same preheat 215°C, 100g charge, same fan/RPM/drum, same target color range.", "variable_changed": "Development time only", "levels_tested": "A=0:50\nB=0:40\nC=0:30", "expected_outcomes": "A subtle lift\nB best separation\nC boundary (papery/hollow risk)", "failure_boundary": "papery/hollow, acidity detached, short/astringent finish, obvious underdevelopment", "observed_outcome_a": "Roast aggression reduced relative to #57 and #58. Initial hollowness when hot, but cup filled in as it cooled. Minimal toast, smoke, or bitterness. Shortening dev to 0:50 avoided over-baking and roast dominance, but did not restore acidity, sweetness, or contrast. The cup became safer, not clearer. Cleanest of the set. Still generic and under-expressive. Pourover confirms the cupping result: clean and safe, but generic. Development shortening reduced roast defects without improving varietal clarity or attack.", "observed_outcome_b": "Increased internal “content” vs #56. Baked/toasty character emerged. Acidity and sweetness insufficient to balance. Further dev reduction crossed into a baked zone rather than increasing liveliness. Separation did not improve; finish degraded. More flavor mass, worse balance. Pourover shows #57 marginally smoother and more blended than #56, but equally flat. Reduced development increases cohesion, not expressiveness. Gains drinkability, not distinction.", "observed_outcome_c": "Dominant toast, smoke, bitterness. No sweetness or acidity recovery. Clear boundary failure. Dev too short for this curve shape and energy distribution. Hard stop. Not viable.", "winner": "Batch #56 (0:50 Dev) Lowest toast and most drinkable, but not more expressive. Best of the set by absence of flaws, not presence of character. Still not reference quality.", "key_insight": "Flatness in this Java is not a development-time issue. Shortening development increases blending and safety, not clarity or attack. The expressive ceiling is governed by RoR shape and energy distribution before and through Maillard.", "what_changes_going_forward": "Lock development back near ~1:00 as a structural constant. Stop spending cycles shortening dev to chase separation. The lever you need is RoR shape through late yellow → Maillard, not dev length. Future experiments should focus on: Smoother RoR decline into first crack. Slightly more energy before Maillard, not less after. Restoring attack vs body contrast without reintroducing toast. This experiment successfully closed a branch of the search tree. Pourover confirms that smoother integration without attack produces a “nice but generic” cup. Future work must restore contrast (attack vs body), not further soften integration."}, {"experiment_id": "JAVA-ROR-SMOOTH-01", "batch_ids": "63, 64, 65", "context": "Your Batch #57 (same base as #46) shows a RoR “kink” from late drying into early Maillard. You want a smoother, continuously declining RoR into first crack, without accidentally creating smoky cups or pushing into thin/papery territory.", "primary_question": "Which single lever best removes the late-drying/early-Maillard RoR dip on this coffee and machine: a small Maillard energy “bridge,” a stronger bridge, or a boundary push?", "control_baseline": "Batch #46", "shared_constants": "Shared Constants\nSame green coffee and batch size (100 g)\nSame roaster + drum direction (Classic)\nSame RPM (unchanged)\nSame development target (match Batch #46: 1:00)\nSame drop/end condition style (drop on dev time)\nSame inlet start and peak targets unless modified below\nSame ambient/setup as much as possible", "variable_changed": "Inlet-temperature curve shaping during early Maillard (a “bridge hold + stepped decline”).\nEverything else stays constant.", "levels_tested": "A - Small tweak (minimal bridge)\nInlet temp points:\n00:00 192°C\n04:15 253°C\n05:00 253°C (hold peak +45s)\n06:45 249°C\n07:30 248°C\n12:00 248°C\nFan: keep your current constant fan (leave at 90% if that’s what you’ve been running)\n\nB - Medium tweak (recommended bridge)\nInlet temp points:\n00:00 192°C\n04:15 253°C\n05:15 253°C (hold peak +60s)\n06:45 250°C\n07:30 248°C\n12:00 248°C\nFan: same as baseline (constant)\n\nC - Boundary push (strong bridge / more energy carried)\nInlet temp points:\n00:00 192°C\n04:15 253°C\n05:45 253°C (hold peak +90s)\n06:45 251°C\n07:45 248°C\n12:00 248°C\nFan: same as baseline (constant)", "expected_outcomes": "A: Slightly smoother RoR through yellow -> Maillard, Minimal timing drift (FC stays close to baseline), Small improvement in clarity vs roastiness\nB: RoR becomes a clean, continuous downward slope (your “purple line”), FC arrives a touch earlier or similar, but less “stall then catch-up” behavior, Cleaner cup, less roast-smoke character\nC: RoR stays elevated longer (no dip), but risk of overshooting, FC likely earlier, Cup risk: more roast development character, or conversely thinner if you compress too hard and lose sugar browning balance", "failure_boundary": "Any of the below:\nFirst crack shifts earlier by >30-40s relative to baseline and cup gets thin/hollow/papery\nRoast-smoke / rubber / ash increases vs baseline\nRoR spikes or crashes (more unstable than baseline)\nLoss of sweetness or cohesion (acidity detached)\n“Baked” signature increases (flat, toast-forward, low sweetness) even if smoke doesn’t spike\nAroma goes rubbery/campfire again", "observed_outcome_a": "Batch 63 (Small Bridge) – Small Maillard bridge successfully introduces citrus for the first time, appearing earlier in the cup (attack / front of body). However, body remains dominant and tannic dryness persists. Structure improves, but balance is incomplete.", "observed_outcome_b": "Batch 64 (Medium Bridge) – Increased Maillard energy smooths and integrates the cup but suppresses citrus expression. Body becomes heavier, tannins increase with cooling, and the cup degrades over time. Pleasant but less expressive than A or C.", "observed_outcome_c": "Batch 65 (Strong Bridge) – Strong Maillard bridge produces the most complete expression yet. Citrus appears throughout the cup rather than on the attack, body lightens, tannins reduce, and overall balance improves. Best clarity-to-structure ratio observed so far.", "winner": "* Immersion cupping winner: Batch #65 (C)\n* Pourover winner: Batch #63 (A)\n* Decision: carry both forward as “two targets” until you validate with a dialed pourover recipe (one attack-forward, one body-forward)", "key_insight": "Smoothing the RoR through late drying → Maillard fundamentally changes how this Java expresses acidity. Early citrus appears with a small bridge (A), while integrated citrus and balance appear with a stronger bridge (C). The coffee does not respond linearly: medium bridging (B) over-integrates body and suppresses clarity. This Java prefers controlled momentum carry, not mid-range smoothing. The bridge lever changes expression in immersion, but in pourover the strong bridge (C) introduces harshness and suppresses perceived clarity, while the small bridge (A) preserves smoothness and seems more “pushable.”", "what_changes_going_forward": "Future work should focus on dialing where citrus sits in the cup, not whether it exists.\n* To emphasize attack: slightly reduce bridge strength toward Batch #63 behavior\n* To emphasize balance and elegance: stay close to Batch #65\n* Avoid mid-range bridges that increase body without unlocking clarity\nNext experiments should:\n* Fine-tune bridge duration (±15–20s) rather than magnitude\n* Explore micro-adjustments to late Maillard decline slope\n* Make pourover the primary arbiter for this coffee going forward. Immersion is directionally useful but overstates how well the strong-bridge profiles translate to percolation."}, {"experiment_id": "JAVA-ROR-REFINE-63-01", "batch_ids": "78, 79, 80", "context": "Batch #63 (Small Bridge) produced the most promising roast so far. Under percolation (V60), it expressed sweet orange jam, lemon, lime, and tea structure with good integration and sweetness. The goal is no longer to “unlock acidity,” but to refine citrus placement and balance.", "primary_question": "Around the proven Batch #63 profile, does slightly shortening or slightly extending the Maillard bridge improve attack clarity or jam depth without introducing tannin, harshness, or roast dominance?", "control_baseline": "Batch #63", "shared_constants": "Same green coffee and batch size (100 g)\nSame roaster (Roest L200 Ultra)\nSame drum direction and RPM\nSame fan setting\nSame peak inlet temperature (253°C)\nSame development time (~1:00)\nSame drop strategy (drop on dev time)\nSame preheat and ambient setup", "variable_changed": "Maillard bridge duration only (hold time at peak before decline)", "levels_tested": "A – Replication (Control Confirmation)\nExact Batch #63 profile\n\nB – Earlier Maillard Drop (–15 to –20 seconds bridge)\n05:00 hold unchanged\n06:30 → 249°C (instead of 06:45)\nRemainder identical\n\nC – Longer Bridge (+15 to +20 seconds hold)\n05:15–05:20 hold at 253°C\nStep-down shifted accordingly\nRemainder identical", "expected_outcomes": "A – Should reproduce sweet orange jam, lemon/lime layering, smooth tea body. Confirms stability of reference roast.\n\nB – Slightly more forward citrus attack, brighter expression, potentially more definition at front of cup. Risk: sharper tannin or thinner mid-palate.\n\nC – Deeper jam integration, rounder sweetness, slightly more mid-palate density. Risk: muted attack or heavier tea character.", "failure_boundary": "Citrus disappears or becomes sour\nTannin dryness increases noticeably\nRoast/toast signature returns\nCup becomes hollow or papery\nJam sweetness collapses into generic nutty profile", "observed_outcome_a": "Outcome A – Replication (#78)\nReplication introduced more roast/smoke character than original Batch #63. Brightness present but partially masked. Drying oversteep character noticeable. Did not fully reproduce original clarity.", "observed_outcome_b": "Outcome B – Earlier Drop (#79)\nCleaner and slightly more integrated than replication. Citrus and sweetness more apparent as cup cooled. Still slight drying/harsh quality. Improvement over A but not fully resolved.", "observed_outcome_c": "Outcome C – Longer Bridge (#80)\nSweetest and roundest cup of the set. Fruit expression broadened beyond citrus into general fruit sweetness. Least harshness of the three, though slight oversteep character remains. Most balanced overall.", "winner": "Batch #80 (Longer Bridge)\nWith note:\nWhile earlier hypothesis suggested shorter bridge might increase attack, this cupping shows slightly longer bridge improved sweetness and balance, though at the expense of sharp citrus definition.", "key_insight": "Minor Maillard bridge extension increases sweetness and roundness more reliably than shortening the bridge increases citrus attack. However, all three roasts show mild drying character, suggesting overall roast depth drifted slightly darker than optimal.\nThat last sentence is important.\nBecause looking at the roast data:\n* Weight loss jumped from ~11.2% to ~12.4–12.5%\n* Agtron drifted darker\n* First crack moved later\nThat is not trivial.\nThat likely explains the shared oversteep dryness.", "what_changes_going_forward": "* The optimal expression likely sits slightly lighter than these three roasts.\n* Future refinement should maintain Batch #80 bridge duration but reduce overall roast depth (target ~11.5–11.8% weight loss).\n* Control of total roast time is more important than bridge duration alone."}, {"experiment_id": "JAVA-COUNTERFLOW-MAILLARD-01", "batch_ids": "82, 84, 86, 88", "context": "Previous roasts of the El Socorro Java showed strong citrus potential (sweet orange, lime, orange marmalade) but increasing roast character and dryness in later roasts. The working hypothesis was that earlier roast structures allowed too much Maillard residence, muting acidity and introducing roast bitterness.\n\nTo test a structural change rather than incremental tweaks, roasting shifted to counterflow mode on the Roest L200 Ultra. Counterflow increases convective heat transfer and tends to produce: faster drying, earlier yellow, shorter Maillard, earlier first crack.  This roasting style is commonly used by ultra-light roasters such as Sey, Hydrangea, Shoebox, and Picky Chemist who prioritize: early energy, declining RoR, short development, minimal Maillard plateau\n\nThis experiment tested multiple counterflow roast structures to determine which balance of drying speed, Maillard compression, and first crack timing best expresses the citrus-forward profile of this Java lot.\n\nSuccess criteria: Smooth declining RoR after peak without crash or flick, Clear citrus expression with minimal roast character, Target weight loss: ~10.5–11.5%", "primary_question": "Does shortening the Maillard phase through counterflow roasting improve citrus clarity and reduce roast bitterness in this Java lot?", "control_baseline": "None. This experiment intentionally moves away from the previous roasting structure.", "shared_constants": "Roest L200 Ultra\nCounterflow mode\n100 g batch size\nFan: 90%\nDrum speed: 65 RPM\nTarget development 45–50 s", "variable_changed": "Roast energy distribution across drying and Maillard phases through inlet temperature profile adjustments.", "levels_tested": "A - Very fast structure with strongly compressed Maillard.\nB - Slightly moderated energy with modest Maillard expansion.\nC - Further moderated energy producing longer Maillard and later first crack.\nD - Midpoint structure between B and C after observing roast behavior mid-experiment.", "expected_outcomes": "A - Very bright acidity and citrus clarity but risk of thin body or underdevelopment.\nB - High citrus clarity with improved sweetness and slightly more body.\nC - Rounder sweetness and heavier body but potential reduction in citrus brightness.\nD - Balanced structure combining citrus clarity with improved sweetness and integration.", "failure_boundary": "Coffee becomes thin, hollow, grassy, or shows roast bitterness.\nWeight loss exceeds ~12.3% or falls below ~10%.\nRoR crash before first crack or flick after first crack.", "observed_outcome_a": "Batch 82: Clearly underdeveloped. Dominant grassy/vegetal character. Roast progressed too quickly for proper internal development.", "observed_outcome_b": "Batch 84: Slightly improved but still underdeveloped. Nutty/grassy with minimal acidity or sweetness.", "observed_outcome_c": "Batch 86: First structurally successful roast. Clean acidity and good separation in immersion cupping but thin body in pour-over brewing.", "observed_outcome_d": "More developed and complete. Better sweetness and body, orange-like acidity present but muted. Slight dryness/bitterness emerges", "winner": "Batch 88: Slightly fuller development and body with more sweetness and orange-like acidity but introduces mild dryness.", "key_insight": "Batch 86 and 88 both successful in different ways; ideal roast likely between them.", "what_changes_going_forward": "Counterflow roasting significantly compresses Maillard and accelerates first crack timing. Very fast structures (82/84) produce underdevelopment. Balanced structures near 86–88 produce the best clarity. Brewing method strongly affects perception: immersion emphasizes citrus clarity while pour-over exposes body and development differences."}]') AS rec(
    experiment_id text, batch_ids text, context text, primary_question text,
    control_baseline text, shared_constants text, variable_changed text,
    levels_tested text, expected_outcomes text, failure_boundary text,
    observed_outcome_a text, observed_outcome_b text, observed_outcome_c text,
    observed_outcome_d text, winner text, key_insight text, what_changes_going_forward text
  )
ON CONFLICT (user_id, green_bean_id, experiment_id) DO NOTHING;

-- Libertad - Aurelio Del Cerro (7 rows, lot_id = 'GUA-LIB-ADC-2024')
WITH bean AS (SELECT id AS green_bean_id, user_id FROM green_beans WHERE lot_id = 'GUA-LIB-ADC-2024')
INSERT INTO experiments (
  user_id, green_bean_id,
  experiment_id, batch_ids, context, primary_question, control_baseline,
  shared_constants, variable_changed, levels_tested, expected_outcomes,
  failure_boundary, observed_outcome_a, observed_outcome_b, observed_outcome_c,
  observed_outcome_d, winner, key_insight, what_changes_going_forward
)
SELECT
  bean.user_id, bean.green_bean_id,
  rec.experiment_id, rec.batch_ids, rec.context, rec.primary_question, rec.control_baseline,
  rec.shared_constants, rec.variable_changed, rec.levels_tested, rec.expected_outcomes,
  rec.failure_boundary, rec.observed_outcome_a, rec.observed_outcome_b, rec.observed_outcome_c,
  rec.observed_outcome_d, rec.winner, rec.key_insight, rec.what_changes_going_forward
FROM bean,
  jsonb_to_recordset('[{"experiment_id": "LIBERTAD-BOURBON-AIR-01", "batch_ids": "41, 42, 43", "context": "After establishing Batch #35 as a stable, clean reference, multiple roasts of Guatemala Libertad Bourbon continued to present as bright, acidity-forward, and light-bodied, with limited mid-palate weight and sugar depth. Prior airflow and development changes produced only subtle differences that converged as the cups cooled. This experiment isolates three structural levers—late volatile removal, mid-phase sugar development, and early bean momentum—to determine which meaningfully alters body integration and finish while preserving the coffee’s tangerine/floral character.", "primary_question": "Which structural lever—late airflow, mid-phase airflow reduction, or increased early inlet energy—most improves body integration and finish in Guatemala Libertad Bourbon without muting clarity or introducing heaviness?", "control_baseline": "Batch #35 (Guatemala Libertad – A)", "shared_constants": "Same green coffee and batch size (100 g)\nSame roaster (Roest L200 Ultra)\nSame preheat and drum conditions\nSame inlet curve (unless explicitly modified)\nSame RPM, drum direction\nSame target development time (~0:50)\nOne variable changed per batch only", "variable_changed": "A: Late-phase airflow\nB: Mid-phase airflow (Maillard)\nC: Early inlet energy", "levels_tested": "A – Batch #41 - Late-high airflow Fan: Charge → yellow: 90% Yellow → first crack: 90% Post-first crack: 100%\nB – Batch #42 Mid-phase airflow reduction Fan: Charge → yellow: 90% Yellow → first crack: 80% Post-first crack: 90%\nHigher early inlet energy Inlet: 00:00 → 195°C (vs 190°C baseline) All other inlet points unchanged Fan 90% flat", "expected_outcomes": "A Cleaner finish Improved aromatic lift Reduced sour carryover Risk: lighter mid-palate\nB Improved sugar development More connected mid-palate Slightly heavier finish Risk: reduced clarity if pushed too far\nC Improved internal bean development Fuller mid-palate without airflow changes Risk: sharper acidity if early energy is excessive", "failure_boundary": "Pourover translation improved vs spoon cupping.\nLight body, some sweetness, cleaner finish than 43.\nAcidity shows on attack but fades in the body.\nPersistent ‘black tea dryness’ with an oversteeped-tea finish.\nBest overall balance of the surviving roasts.", "observed_outcome_a": "Smoky and slightly bitter body character\nAcidity muted initially, then emerges without integration\nHollow mid-palate\nSlight improvement as cup cools, but persistent astringency\nCleaner than Batch 42, but still unbalanced", "observed_outcome_b": "Strongest roast imprint of the three\nSmoky, roasty body with hollow center\nAcidity increases on cooling but clashes with body\nLowest sweetness and poorest balance\nClear overcorrection away from clarity", "observed_outcome_c": "Strong roast/toast aroma and flatter early cup.\nImproves substantially as it cools; acidity/sweetness show late.\nMore body than 41 but body character partially obscured by roast imprint.\nBetter at cooler temps than warm; less oversteep dryness than 41.", "winner": "Batch #41\n(Best of a weak set; not a final target profile.)", "key_insight": "Airflow manipulation (late-high or mid-reduction) is high risk on this coffee - it tends to trade clarity for roast imprint without reliably adding sweetness or weight.\n\n43’s ‘late bloom’ (good only when cool) is a warning sign: some profiles are not failing structurally, they are failing in hot-cup expression and aromatics.\n\n41 suggests late cleanup airflow can help, but it can also thin the mid-palate and create tea-dryness if the roast is already on the edge.", "what_changes_going_forward": "Use airflow as a finish/cleanup tool only, and keep changes larger only when you’re explicitly mapping boundaries.\n\nIf you need more body and sugar depth, pursue energy/shape and development ladders (like 48-50, and your dev ladder off 49), not airflow restriction.\n\nWatch for ‘oversteeped tea dryness’ in pourover as a failure marker, not only bitterness."}, {"experiment_id": "LIBERTAD-BOURBON-SPECTRUM-01", "batch_ids": "48, 49, 50", "context": "After reviewing Rob Hoos’ observations on Bourbon in Cultivar, this experiment set tests whether prior roast approaches were biasing the coffee toward a clean, modern, acidity-forward profile rather than a Bourbon-typical expression. Across multiple earlier batches, the coffee presented as bright and light-bodied, with limited mid-palate weight and sugar depth, and cups converged as they cooled. These three roasts intentionally increase adjustment magnitude from subtle to extreme to map where this coffee sits on the Bourbon spectrum and define both optimal expression and upper development boundaries.", "primary_question": "Which roasting lever—mid-phase airflow, gentler Maillard energy, or extended development—most meaningfully shifts Guatemala Libertad toward a Bourbon-typical expression (caramel sweetness, integrated body) without tipping into heaviness or savory notes?", "control_baseline": "Batch #35 (Guatemala Libertad – A)", "shared_constants": "Same green coffee and batch size (100 g)\nSame roaster (Roest L200 Ultra)\nSame preheat and drum conditions\nSame RPM and drum direction\nSame general inlet curve shape (unless explicitly modified)\nSame fan baseline (90%) unless explicitly modified\nOne variable changed per experiment only", "variable_changed": "A: Mid-phase airflow (Maillard convection)\nB: Inlet energy slope through Maillard\nC: Development time (post-first crack)", "levels_tested": "A – Batch #48 (Fine Adjustment) Mid-phase airflow reduction Fan: Charge → yellow: 90% Yellow → first crack: 85% Post-first crack: 90%\nB – Batch #49 (Medium Adjustment) Gentler Maillard via inlet slope Inlet: 0:00 – 190°C 5:00 – 255°C (down from 260°C) 7:30 – 250°C 12:00 – 248°C Fan stays flat at 90%\nC – Batch #50 (Boundary Push) Extended development only Dev time: ~1:25 Inlet identical to baseline Fan flat at 90%", "expected_outcomes": "A Improved mid-palate integration Cleaner, rounder finish Minimal change in brightness\nB Clear caramel sweetness More cohesive structure Acidity integrated rather than leading\nC Dried fruit replaces fresh fruit Sweetness deepens toward molasses Nutty notes increase Risk of dull acidity and heavy finish", "failure_boundary": "Sweetness collapses relative to acidity\nAcidity dulls or becomes savory\nMid-palate becomes heavy or muddy\nFinish turns flat, drying, or roast-driven\nLoss of defining fruit character", "observed_outcome_a": "Strong citrus/floral attack when hot, nutty body.\nAttack-body separation and a bitter “roasted nut/chestnut” note through finish.\nLoses some peak brightness as it cools, yet still shows real character.", "observed_outcome_b": "Smoke/roast dominates aroma and cup.\nFlat and monotone through most temps.\nAstringent mouthfeel and lingering drying quality.\nOnly at very cool temps does faint acidity/sweetness show, still blocked by roast imprint.", "observed_outcome_c": "Roast imprint dominates\nFruit expression suppressed\nDefines clear upper boundary for this coffee", "winner": "Batch 48", "key_insight": "This coffee’s “survivor” decision needs a pourover gate. Regular cupping alone over-selected 49.\nThe gentler Maillard inlet-slope approach (49) produced roast-forward smoke and drying astringency in pourover, suggesting the curve shape pushed flavor toward roast imprint rather than integrated sweetness in your brew format.\nAirflow tweak (48) preserved more origin character, but mid-palate integration and bitter roast-nut finish still need work.", "what_changes_going_forward": "Use two-stage selection:\nStage 1: standard cupping to eliminate defects.\nStage 2: pourover cupping to pick the forward path.\n\nDeprioritize the exact #49 inlet-slope as a “Bourbon-forward” template.\nContinue from #48 as the better sensory base, then target one structural fix:\nReduce attack-body separation.\nRemove roast-nut bitterness without flattening acidity.\nNext experiment direction suggestion (one lever at a time):\n\nKeep the #48 airflow approach, then test early-energy shaping (fine/medium/hard) to improve internal development and mid-palate without adding smoke."}, {"experiment_id": "LIBERTAD-BOURBON-DEV-02", "batch_ids": "59, 60, 61", "context": "Batch 49 showed the most stable integration and improved as it cooled, but was muted and roasty when hot. This suggests internal development was improved, but aromatic lift and “hot cup” clarity lagged. This experiment maps whether a shorter vs longer post-first crack development restores lift while preserving the integrated Bourbon-leaning structure.", "primary_question": "How sensitive is this coffee to development time, and where is the boundary where added development shifts from “more integrated” to “flat/roast-driven”?", "control_baseline": "Batch 49", "shared_constants": "Development time (post-first crack) only", "variable_changed": "Development time (post-first crack) only", "levels_tested": "A - Fine adjustment: shorter dev (lift test)\nDev time: 0:40 (down from 0:50)\nEverything else identical to Batch 49\n\nB - Medium push: slightly longer dev (integration test)\nDev time: 1:05\nEverything else identical to Batch 49\n\nC - Hard push: boundary probe (heaviness test)\nDev time: 1:25\nEverything else identical to Batch 49\n\nNote: you already explored 1:25 once in a different context, but running it off the 49 inlet shape is valuable as a true boundary reference.", "expected_outcomes": "A (0:40)\nMore aromatic lift and clearer citrus earlier (hot cup improves)\nRisk: thinner mid-palate, sharper acidity, “hollow” center\n\nB (1:05)\nSweetness and body knit together better than 49\nAcidity becomes less “late-emerging” and more continuous\nRisk: mild flattening if this coffee is highly dev-sensitive\n\nC (1:25)\nBody and roast-derived notes rise\nFruit shifts from fresh citrus to muted / dried / nutty\nHigh risk of “flat, dull, roast-forward” finish (clear boundary marker)", "failure_boundary": "Roast imprint dominates (toasty/smoky/nutty replaces fruit)\nCup gets flatter as it cools (inverse of your goal)\nAcidity disconnects from sweetness (sharp/sour carryover)\nFinish turns drying or dull\nLoss of the citrus/orange character you’re tracking", "observed_outcome_a": "Clearer citrus direction than 60, but weak attack in pourover Acidity presents as underlying orange peel rather than front-loaded snap Finish collapses into oversteeped tea dryness → Confirms shorter dev restores acidity cues, but structural continuity is still lacking\nThis aligns with what you actually tasted.", "observed_outcome_b": "Fuller body and smoother mouthfeel than 59 Citrus expression largely suppressed Oversteeped tea dryness more pronounced, especially as it cools → Confirms additional development increases body but accelerates dryness and mutes expression. This is important. 60 is not a balance point.", "observed_outcome_c": "Body and nutty/baked notes dominate\nAcidity suppressed; cup trends flat and heavy\nClear overbaked character emerges\n→ Confirms upper development boundary; not a viable direction. No additional pourover done.", "winner": "No true winner. Batch 59 shows preferable acidity direction. Batch 60 shows preferable body continuity. Neither achieves integration without oversteeped dryness.\nThis matters philosophically. You have not solved the problem yet.", "key_insight": "Development time alone does not resolve this coffee’s structural dryness. Shorter dev (59) restores acidity direction but collapses into drying tea notes. Longer dev (60) improves body but suppresses citrus and intensifies dryness. The recurring oversteeped tea character indicates a mid-roast energy continuity issue, not a post-crack duration issue. This is the pivot.", "what_changes_going_forward": "You stop iterating on development length and move fully into RoR / Maillard continuity tuning. Why:\n* Dryness shows up at both short and longer devs\n* That means it is being created before first crack\n* Development is only revealing it, not causing it"}, {"experiment_id": "LIBERTAD-BOURBON-ROR-DEV-01", "batch_ids": "67, 68, 69", "context": "Prior batches showed signs of mid-roast energy sag, leading to cups that expressed as bright but structurally fragile, drifting into black-tea dryness or muted roast tone as they cooled. Recent adjustments to Maillard pacing improved internal development and integration, but highlighted sensitivity to post-first-crack development length. This experiment uses a revised inlet curve to stabilize roast momentum (smooth, continuously declining RoR into first crack), then isolates development time as the sole remaining variable to define the balance point between citrus lift and Bourbon-leaning tea/caramel depth.", "primary_question": "With a stabilized inlet curve and smooth RoR into first crack, what development time (0:40 vs 0:55 vs 1:05) best preserves citrus clarity and aromatic lift while avoiding hollowness, oversteeped tea dryness, or roast-derived flattening?", "control_baseline": "Batch 60", "shared_constants": "Same green coffee and batch size (100 g).\nSame roaster (Roest L200 Ultra).\nSame preheat temperature.\nSame drum direction (Classic).\nSame RPM.\nSame fan profile (90% flat).\nSame charge conditions.\nSame revised inlet curve for all three roasts.\nSame first-crack approach and drop logic (end condition = development time only).\nSame rest and evaluation protocol.", "variable_changed": "Development time", "levels_tested": "A: 0:40 – lift boundary (maximum acidity expression test)\nB: 0:55 – center point (balance of lift + structure)\nC: 1:00 – integration reference", "expected_outcomes": "A: Highest perceived citrus snap and aromatic lift; risk of thinner mid-palate or slight sharpness.\nB: Best balance of acidity, sweetness, and body; expected “lockable” profile.\nC: Increased tea/caramel depth and cohesion", "failure_boundary": "Hollow or papery mid-palate.\nAcidity detaches from sweetness or turns sour.\nFinish becomes drying or astringent (oversteeped black-tea character).\nRoast/toast dominates aromatics.\nCup flattens or loses clarity as it cools.", "observed_outcome_a": "Observed Outcome A – Batch 67 (0:40)\nHigh clarity lemon expression and smooth integration. Best performance when hot. Slight flattening and loss of citrus emphasis as cup cools. Very clean finish with no structural dryness. Confirms shorter development maximizes lift but slightly reduces temperature stability.", "observed_outcome_b": "Observed Outcome B – Batch 68 (0:55)\nMore muted hot, but strongest improvement through cooling. Citrus intensifies as temperature drops. Fuller body and better persistence across temperature range. Represents most stable real-world drinking profile.", "winner": "Batch 67 and 68 both viable. 67 = smooth, elegant, hot-cup preference. 68 = more stable, expressive through full drinking arc.\nIf forced to choose one for real-world use: 68 is slightly more versatile.", "key_insight": "The revised inlet curve successfully removed structural dryness from earlier experiments. Development is now a flavor-shaping lever, not a corrective tool.\nThe optimal window is tight: ~0:40–0:55.\nThe difference between 67 and 68 is not structural — it is temperature behavior and emphasis.\nThis coffee’s ceiling is pleasant clarity and drinkability, not explosive differentiation. Roast adjustments now yield nuance, not transformation.", "what_changes_going_forward": "• Lock this inlet curve as the baseline • Keep development between 0:45–0:55 for future production • Tune expression via:\n* Slight Maillard pacing shifts\n* Subtle airflow adjustments post-yellow\n* Brew parameters rather than longer development\nYou are no longer fixing defects. You are choosing stylistic direction."}, {"experiment_id": "LIBERTAD-BOURBON-ACIDITY-AIRFLOW-01", "batch_ids": "75, 76, 77", "context": "Batches 67 (0:40) and 68 (0:55) on the revised inlet curve produced clean, citrus-forward cups with no structural dryness. 67 peaked hot. 68 improved as it cooled. The goal now is not more caramel or nut depth. The goal is to push citrus lift and acidity clarity. Airflow is isolated as the next lever while keeping development in the proven window.", "primary_question": "With the revised inlet curve locked and development held constant, how does increased airflow through Maillard affect citrus lift and aromatic clarity versus risk of thinness or sharpness?", "control_baseline": "Batch 68 (0:55 dev)", "shared_constants": "Same green coffee and 100 g batch size\nSame roaster (Roest L200 Ultra)\nSame preheat (215C)\nSame drum direction (Classic)\nSame RPM\nSame charge conditions\nSame inlet curve:\n00:00 – 192C\n04:15 – 253C\n06:30 – 252C\n08:30 – 250C\n12:00 – 248C\nSame development time: 0:50 (center of 67–68 window)\nSame drop logic (development time only)\nSame rest and evaluation protocol\nEvaluation at ~60C and ~50C, cupping + pourover", "variable_changed": "Airflow (fan %) during Maillard", "levels_tested": "A - 90% flat (baseline reference)\nB - 95% flat (full acidity push)\nC - 95% from yellow to first crack, then back to 90% post-crack (targeted acidity push)", "expected_outcomes": "A - Balanced citrus and structure; strong clarity but not maximum lift\nB - Highest aromatic lift and lemon peel intensity; fastest, brightest expression; risk of thinner mid-palate\nC - Similar lift to B with slightly better cohesion; cleaner finish than B", "failure_boundary": "Primary failure (not acceptable):\nCitrus lift decreases and nut/tea dominates\nRoast tone appears\nFinish becomes drying or dull\nCup flattens as it cools\n\nAcceptable failure (pushing acidity):\nToo sharp or too zesty\nSlightly hollow mid-palate\nShorter finish", "observed_outcome_b": "Highest citrus clarity and separation in pourover. Expressive orange acidity with strong attack. Minor roast tone and slight harshness as cup cools. Most aligned with acidity-first objective.", "observed_outcome_c": "Slightly more integrated in immersion, but less expressive in pourover. Rounder but less clean separation. Persistent integration issue across temperatures. Does not outperform 76 in real-world brew format.", "winner": "Batch 76 – Preferred under pourover evaluation \nBatch 77 – Performs better in immersion than pourover\nYou cannot claim 77 as overall winner anymore. Your end goal is pourover performance.", "key_insight": "High flat airflow (95%) increases citrus separation and improves pourover clarity. Targeted airflow step-down introduced integration instability in extraction. Airflow timing affects not only development but extraction behavior.\nThis is more important than the earlier conclusion.", "what_changes_going_forward": "* Keep 95% flat airflow as the working acidity reference.\n* Do not reduce airflow post-crack.\n* Next refinement lever should be development time adjustment (0:45–0:47).\n* Objective: reduce slight harshness while preserving citrus separation."}, {"experiment_id": "LIBERTAD-BOURBON-ACIDITY-DEV-TRIM-02", "batch_ids": "TBD", "context": "Batch 76 (95% flat airflow, 0:50 dev) produced strong citrus separation and high acidity in pourover, with minor roast tone and slight harshness at lower temperatures. Objective is to maintain airflow-driven citrus lift while reducing roast intensity and smoothing finish. This experiment trims development more aggressively to locate the lower structural boundary.", "primary_question": "With airflow locked at 95% flat and inlet curve unchanged, how far can development be reduced (0:50 vs 0:45 vs 0:40) before structure collapses or acidity becomes sharp and detached?", "control_baseline": "Batch 76 (0:50 dev)", "shared_constants": "Same green coffee and 100 g batch size\nSame roaster (Roest L200 Ultra)\nSame preheat (215C)\nSame drum direction (Classic)\nSame RPM\nSame charge conditions\nSame inlet curve:\n00:00 – 192C\n04:15 – 253C\n06:30 – 252C\n08:30 – 250C\n12:00 – 248C\nSame airflow: 95% flat throughout\nSame drop logic (development time only)\nSame rest and evaluation protocol\nEvaluation via pourover first, then immersion", "variable_changed": "Development time only", "levels_tested": "A – 0:50 (baseline reference)\nB – 0:45 (moderate trim)\nC – 0:40 (aggressive trim)", "expected_outcomes": "A – Known expression: strong citrus, slight roast edge, minor harshness at lower temp\nB – Reduced roast tone, cleaner finish, preserved citrus separation; likely optimal\nC – Maximum lift and sharpness; risk of hollow mid-palate, shorter finish, or detached acidity", "failure_boundary": "Not acceptable:\nCitrus drops or becomes dull\nMid-palate collapses into hollow or papery texture\nAcidity turns sour or disconnected\nFinish becomes thin and abrupt\n\nAcceptable (since acidity-first bias):\nSlightly sharper attack\nShorter finish\nLighter body", "what_changes_going_forward": "If 0:45 wins → lock as production dev time.\nIf 0:40 still holds structure → consider slight inlet compression to enhance clarity further.\nIf 0:40 collapses → you’ve defined lower structural boundary clearly."}, {"experiment_id": "LIBERTAD-COUNTERFLOW-DEVELOPMENT-01", "batch_ids": "89, 91, 93, 94", "context": "Previous roasts of this washed Guatemala Bourbon/Caturra finished darker than desired and showed mild roast character and dryness masking acidity. The hypothesis was that the Maillard phase and post-crack development were carrying too much thermal momentum. Counterflow roasting was introduced to stabilize heat transfer and test whether compressing development time could achieve lighter roast color and improved clarity.", "primary_question": "How much can development time be reduced under a counterflow roasting structure while maintaining a stable declining RoR and improving roast color and clarity?", "control_baseline": "None. This experiment intentionally moves away from the previous roasting structure.", "shared_constants": "100 g batch size\nRoest L200 Ultra\nCounterflow drum direction\nCharge ~109°C\nFan ~90%\nRPM ~65\nSimilar inlet trajectory\nDeclining RoR structure\nSame green coffee lot", "variable_changed": "Development time and first-crack entry temperature", "levels_tested": "A – Batch 89 - 45 s development, higher FC temperature (~210°C)\nB – Batch 91 - 45 s development, slightly later FC timing\nC – Batch 93 - 45 s development with lower FC temperature (~206°C)\nD – Batch 94 - 25 s development, compressed development phase", "expected_outcomes": "A/B: darker medium-light color \nC: slightly lighter due to lower FC temp \nD: significantly lighter roast with lower weight loss", "failure_boundary": "Roast color darker than medium-light (Agtron <65)\nRoR crash or stall after first crack\nUneven RoR behavior indicating unstable heat transfer", "observed_outcome_a": "Observed Outcome A (Batch 89)\n\nRoast showed stable curve but strong roast character and dryness.\nCitrus notes present but masked by roast tone.\nCup improved slightly as it cooled but remained the weakest of the set.", "observed_outcome_b": "Observed Outcome B (Batch 91)\n\nCleaner than Batch 89 with noticeable sweetness and citrus character.\nHowever slight bitterness remained and clarity was lower than later roasts.\nDevelopment length still produced mild caramelization.", "observed_outcome_c": "Observed Outcome C (Batch 93)\n\nBatch 93 produced strong citrus expression in immersion cupping but showed clear instability in pourover. Lactic/cheese-like off-flavor and lack of clean acidity indicate insufficient internal development. Structure does not hold under extraction.", "observed_outcome_d": "Observed Outcome D (Batch 94)\n\nBatch 94 eliminated the lactic defect seen in Batch 93 and produced a cleaner, more stable cup. However, the profile is slightly muted and body-heavy with mild roast tone. More developed than 93, but still not fully optimized for clarity.", "winner": "Batch 94 – most stable and drinkable under pourover. Batch 93 – rejected due to structural instability (underdevelopment)", "key_insight": "Under counterflow roasting, development time becomes the dominant lever controlling roast color and caramelization. Reducing development from ~45 s to ~25 s significantly lowered weight loss and removed roast character, enabling clearer acidity expression. Lower FC temperature also contributed to improved clarity.", "what_changes_going_forward": "Future roasts of this coffee should:\n\nMaintain counterflow roasting structure\nTarget development times around 20–30 s\nEnter first crack around ~206–208C\nMaintain balanced drying and Maillard phases\n\nThis structure produces the best clarity and citrus expression for this coffee.\n\nTo carry forward to the pourover cupping - 93 and 94"}]') AS rec(
    experiment_id text, batch_ids text, context text, primary_question text,
    control_baseline text, shared_constants text, variable_changed text,
    levels_tested text, expected_outcomes text, failure_boundary text,
    observed_outcome_a text, observed_outcome_b text, observed_outcome_c text,
    observed_outcome_d text, winner text, key_insight text, what_changes_going_forward text
  )
ON CONFLICT (user_id, green_bean_id, experiment_id) DO NOTHING;

-- Gesha Village - Oma - Gesha 1931 (3 rows, lot_id = 'GV-OMA-25-035')
WITH bean AS (SELECT id AS green_bean_id, user_id FROM green_beans WHERE lot_id = 'GV-OMA-25-035')
INSERT INTO experiments (
  user_id, green_bean_id,
  experiment_id, batch_ids, context, primary_question, control_baseline,
  shared_constants, variable_changed, levels_tested, expected_outcomes,
  failure_boundary, observed_outcome_a, observed_outcome_b, observed_outcome_c,
  observed_outcome_d, winner, key_insight, what_changes_going_forward
)
SELECT
  bean.user_id, bean.green_bean_id,
  rec.experiment_id, rec.batch_ids, rec.context, rec.primary_question, rec.control_baseline,
  rec.shared_constants, rec.variable_changed, rec.levels_tested, rec.expected_outcomes,
  rec.failure_boundary, rec.observed_outcome_a, rec.observed_outcome_b, rec.observed_outcome_c,
  rec.observed_outcome_d, rec.winner, rec.key_insight, rec.what_changes_going_forward
FROM bean,
  jsonb_to_recordset('[{"experiment_id": "GV-OMA-BASE-01", "batch_ids": "52, 53, 54", "context": "First roasts of Oma following a proven Surma Gesha 1931 profile. Objective is not optimization, but mapping the development-time elasticity window relative to a known successful reference. This establishes where aromatics peak, where structure becomes sufficient, and where overdevelopment begins to mute expression.", "primary_question": "Where does Oma’s optimal development window sit relative to a known Surma Gesha benchmark, and how sensitive is it to small changes in post-FC development time?", "control_baseline": "None (new coffee; Surma Batch 25 used only as conceptual reference, not a formal control)", "shared_constants": "Same green lot, batch weight, inlet temperature curve, airflow, RPM, charge/preheat protocol, roast shape, drop criteria by aroma rather than temperature", "variable_changed": "Development time relative to first crack", "levels_tested": "A: ~48–50s dev (early)\nB: ~58s dev (carryover reference)\nC: ~65–68s dev (late)", "expected_outcomes": "A: Maximum aromatic lift, possible sharpness or hollow mid-palate, tests volatility ceiling\nB: Balanced structure with preserved florals, closest to known elastic Gesha behavior\nC: Increased roundness and structure, risk of muted florals or “safe” expression", "failure_boundary": "Underdev: grassiness, sharp unintegrated acidity, hollow body, rapid aromatic fade\nOverdev: nutty/roasty masking, flattened florals, reduced headroom under aggressive brewing", "observed_outcome_a": "Early aromatic ceiling confirmed and survives pourover. Strong floral attack and citrus lift when hot, with dark tea structure underneath. Some mid-finish sharpness persists, but Gesha identity is clearest here. Performs better as a pourover than cupping suggested.", "observed_outcome_b": "Structure-forward profile suppresses florals under pourover. Body and integration dominate, producing a round but generic cup. Oversteeped black-tea character and light bitterness appear as primary notes. Loses Gesha-specific lift.", "observed_outcome_c": "Higher structure but reduced attack. Best hot; weakest cool. Early crack compressed the experiment, but result shows increased integration comes at cost of frontal expression. Aromatics feel contained rather than projected. Did not do a pourover.", "winner": "Roast A – Batch 52 (~48–50s dev)", "key_insight": "Oma’s optimal expression skews earlier than Surma when evaluated under pourover. While 58s dev performs well in cupping, it over-builds structure for brewed contexts, muting floral attack and citrus lift. Oma rewards restraint more than Surma.", "what_changes_going_forward": "Future experiments should anchor around 48–52s dev and focus on smoothing sharpness without adding structure. Secondary levers should aim to soften mid-finish bitterness (post-FC energy taper or gentler early momentum), not extend development."}, {"experiment_id": "GV-OMA-INLET-01", "batch_ids": "72, 73, 74", "context": "Batch 52 (50s dev) is best pourover expression but shows a sharp/oversteep tea note. Oma appears more vigorous and showed early crack variability. This block tests whether the Surma-derived inlet curve is too forceful for Oma, pushing structure/tea notes prematurely.", "primary_question": "With dev held constant (0:50), does reducing peak energy or tapering earlier improve Gesha lift and reduce oversteep/bitterness without hollowing the cup?", "control_baseline": "Batch 52 (0:50 dev, current Rao Test Floral 3 curve)", "shared_constants": "Same green lot, 100 g batch, preheat 215C, fan and RPM unchanged, same charge protocol, same end condition (Dev time), same target dev time 0:50, same drop decision discipline", "variable_changed": "Inlet temperature curve shape (peak magnitude + taper timing)", "levels_tested": "A (Control): Current Rao Test Floral 3 inlet points: 0:00 195C, 5:00 275C, 7:30 263C, 12:00 255C\nB (Lower peak): Reduce 5:00 peak by ~5C (275 -> 270). Keep other points same.\nC (Earlier taper): Keep 5:00 at 275, but pull down earlier: 7:30 point reduced by ~5C (263 -> 258). Keep 12:00 at 255.", "expected_outcomes": "A: Repeats 52 character. Strong floral attack, but oversteep tea/sharpness remains.\nB: Slightly less vigor. Cleaner finish. Less “oversteep” note. Risk: slight loss of lift if too soft early.\nC: Cleaner, more frontal florals. Reduced bitterness/oversteep note. Risk: underbuilt mid-palate if taper is too early.", "failure_boundary": "Any of the following:- Underdev signals: papery/hollow mid-palate, green/vegetal, acidity detaches and feels sour, rapid aromatic fade.- Over-structure signals: florals mute, “generic” cup, persistent black-tea astringency, bitterness grows as it cools.- Process note amplification: medicinal/cheese note becomes more obvious (esp. in aroma and mid-palate).", "observed_outcome_a": "Updated Observed Outcome A (72 – Control)\nBalanced, floral, nutty cup with caramel-tea depth. Clean finish and good inherent drinkability. Not highly explosive but stable across hot and cool. Performs better in pourover than 73 at 8 days rest.", "observed_outcome_b": "Updated Observed Outcome B (73 – Lower Peak)\nHighly expressive in cupping but more muted in pourover. Acidity and sweetness present but require pushing to surface. Rounder structure may slightly suppress immediate floral lift under filter brewing.", "winner": "Batch 72 – Control", "key_insight": "Lowering peak energy increases cupping complexity but does not necessarily translate to better filter performance. The original peak (275°C at 5:00) produces a more inherently expressive and balanced filter cup at 8 days rest. Oma appears less fragile than initially assumed; reducing peak may slightly bury florals under filtration.", "what_changes_going_forward": "* Do not abandon the Surma-derived peak yet.\n* The 275°C peak is not overly aggressive for Oma under filter conditions.\n* Lower peak may require more aggressive brew parameters to unlock.\n* Next refinement should focus on brew optimization before further roast changes.\n* If refining roast further, consider very small peak adjustment (–2°C) rather than –5°C."}, {"experiment_id": "OMA-GESHA-COUNTERFLOW-DEV-01", "batch_ids": "95, 97, 99", "context": "Previous roasts of the Oma Gesha showed strong floral potential and clean citrus structure, but occasionally produced cups with black-tea density and mild roast presence.\n\nThose earlier profiles were roasted using standard drum direction. That approach tended to create a slightly heavier mid-phase structure, producing cups that felt denser than the styles preferred from roasters such as Sey, Moonwake, and Shoebox.\n\nTo test whether roast energy distribution was contributing to that structure, the roasting approach shifted to counterflow drum direction.\n\nCounterflow roasting alters bean movement and heat exposure inside the drum. This often increases early roast heat transfer and reduces reliance on late-stage heat momentum.\n\nThe goal was to determine whether this approach could produce a lighter structural profile while preserving complete development.\n\nTarget cup characteristics: clearer florals, brighter acidity, lighter body, higher clarity\n\nBecause counterflow changes roast thermodynamics significantly, prior roasts were not used as a control baseline. Instead, the first set of roasts mapped the development window under this new roasting model.", "primary_question": "What development time best balances floral clarity, sweetness, and structural completeness when roasting this coffee using counterflow drum direction?", "control_baseline": "None.\n\nSwitching drum direction alters the roast’s heat transfer behavior enough that previous drum-direction roasts cannot serve as a meaningful baseline.\n\nThis experiment serves as the initial mapping of development levels under counterflow roasting.", "shared_constants": "Coffee: Gesha Village - Oma Lot 25/035\nRoaster: Roest L200 Ultra\nBatch size: 100 g\nCharge temperature: ~109°C\nDrum direction: Counterflow\nTarget drop temperature: ~209–210°C\nTotal roast time target: ~4:10\nRoast philosophy: declining RoR with early heat loading", "variable_changed": "Development time after first crack", "levels_tested": "Level A\nRoast Batch: 95\nDevelopment Time: 36 s\nDevelopment %: 14.3%\n\nLevel B\nRoast Batch: 97\nDevelopment Time: 24 s\nDevelopment %: 9.4%\n\nLevel C\nRoast Batch: 99\nDevelopment Time: 40 s\nDevelopment %: 16.1%", "expected_outcomes": "A - Batch 95 - Moderate development\nBalanced sweetness and structure with moderate aromatic clarity.\n\nB - Batch 97 - Ultra-short development\nMaximum aromatic lift but possible reduction in sweetness or mid-palate weight.\n\nC - Batch 99 - Extended development\nGreater sweetness and structural completeness while still maintaining light roast expression.", "failure_boundary": "The roast would be considered unsuccessful if:\n\nRoR crash or flick occurs\nroast character dominates cup profile\nvegetal or underdeveloped flavors appear\nacidity becomes hollow or harsh\n\nNone of the three roasts crossed these boundaries.", "observed_outcome_a": "Observed Outcome A (Batch 95 – 36s) Underdeveloped. Bright but thin with incomplete structure. Lacks sweetness depth and mid-palate weight. Counterflow plus 36s development was still insufficient for full expression.", "observed_outcome_b": "Observed Outcome B (Batch 97 – 24s) Clearly underdeveloped in both cupping and pourover. Very light roast color and clean cup, but flat, monotone, nutty, and incomplete. Lacks sweetness, body differentiation, and distinct Gesha character. Development time was too short.", "observed_outcome_c": "Observed Outcome C (Batch 99 – 40s) Best of the set on initial cupping, with more florality, juiciness, and structure than 95 or 97. However, pourover cupping at 9 days showed it was still monotone, nutty, and incomplete, with only modest acidity and limited Gesha character. This indicates 40s development remained insufficient under counterflow.", "winner": "No true winner. Batch 99 was the best of the set, but still not a successful endpoint.", "key_insight": "Counterflow moved effective heat earlier and preserved very light color, but this coffee still required more post-crack development than expected. Under counterflow, 24s and 36s were clearly too short, and even 40s remained incomplete in pourover. Very light color alone did not translate to floral clarity or Gesha expression. For this coffee, counterflow expanded early energy but did not eliminate the need for sufficient development to build sweetness, differentiation, and structural completeness.", "what_changes_going_forward": "Future counterflow profiles for this coffee should move development later than this test set, likely into the 45–55s range rather than 24–40s. Avoid ultra-short development under counterflow for washed Gesha lots of this type. Next steps should prioritize:\n* testing 45s, 50s, and 55s development under counterflow\n* keeping the same early-energy philosophy while allowing more post-crack completion\n* comparing the best future counterflow roast directly against the best standard drum-direction roast to determine whether counterflow is actually superior for this coffee"}]') AS rec(
    experiment_id text, batch_ids text, context text, primary_question text,
    control_baseline text, shared_constants text, variable_changed text,
    levels_tested text, expected_outcomes text, failure_boundary text,
    observed_outcome_a text, observed_outcome_b text, observed_outcome_c text,
    observed_outcome_d text, winner text, key_insight text, what_changes_going_forward text
  )
ON CONFLICT (user_id, green_bean_id, experiment_id) DO NOTHING;


COMMIT;

